import type { CatalogUiField } from '../types/catalogUiSchema';

/** Case-insensitive, no-diacritics — parity Master `codeField.normalizeSearchText`. */
export function normalizeCatalogSearchText(value?: string): string {
  if (!value) return '';
  return value
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/đ/g, 'd')
    .replace(/Đ/g, 'D')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

function catalogCellDisplayText(row: Record<string, unknown>, field: CatalogUiField): string {
  const value = row[field.key];
  if (field.format === 'activeBadge' || (field.control === 'BOOL' && field.key === 'isActive')) {
    return value ? 'Hoạt động' : 'Ngưng';
  }
  if (field.format === 'sharedScope' || field.key === 'scope') {
    const scope = String(value ?? '');
    if (scope === 'Shared') return 'Dùng chung';
    if (scope === 'Company') return 'Riêng đơn vị';
    return scope;
  }
  if (field.control === 'BOOL') return value ? 'Có' : 'Không';
  if (value == null || value === '') return '';
  return String(value);
}

export function catalogCellDisplayTextForKey(
  row: Record<string, unknown>,
  columns: CatalogUiField[],
  columnKey: string,
): string {
  const field = columns.find(c => c.key === columnKey);
  if (!field) return '';
  return catalogCellDisplayText(row, field);
}

/** Client filter — all visible list columns (+ optional extra strings per row). */
export function filterCatalogListRows<T extends Record<string, unknown>>(
  rows: T[],
  query: string,
  columns: CatalogUiField[],
  extraValues?: (row: T) => string[],
): T[] {
  const q = normalizeCatalogSearchText(query);
  if (!q) return rows;
  return rows.filter(row => {
    const haystack = columns.map(col => catalogCellDisplayText(row, col));
    if (extraValues) haystack.push(...extraValues(row));
    return haystack.some(part => normalizeCatalogSearchText(part).includes(q));
  });
}

export function applyCatalogColumnFilters<T extends Record<string, unknown>>(
  rows: T[],
  columns: CatalogUiField[],
  columnFilters: Record<string, string[]>,
): T[] {
  const active = Object.entries(columnFilters).filter(([, values]) => values.length > 0);
  if (active.length === 0) return rows;
  return rows.filter(row => active.every(([key, allowed]) => {
    const cell = catalogCellDisplayTextForKey(row, columns, key);
    return allowed.includes(cell);
  }));
}

export type ErpListSortState = { columnKey: string; direction: 'asc' | 'desc' } | null;

export function buildCatalogColumnSortCompare<T extends Record<string, unknown>>(
  columns: CatalogUiField[],
  sort: ErpListSortState,
): ((a: T, b: T) => number) | undefined {
  if (!sort) return undefined;
  const field = columns.find(c => c.key === sort.columnKey);
  if (!field) return undefined;
  return (a, b) => {
    const av = catalogCellDisplayTextForKey(a, columns, sort.columnKey);
    const bv = catalogCellDisplayTextForKey(b, columns, sort.columnKey);
    const cmp = av.localeCompare(bv, 'vi', { sensitivity: 'base', numeric: true });
    return sort.direction === 'asc' ? cmp : -cmp;
  };
}

export function applyCatalogColumnSort<T extends Record<string, unknown>>(
  rows: T[],
  columns: CatalogUiField[],
  sort: ErpListSortState,
): T[] {
  const compare = buildCatalogColumnSortCompare<T>(columns, sort);
  if (!compare) return rows;
  return [...rows].sort(compare);
}
